	('9b60acd1-ac57-4620-b960-082fa1d7d5e5', 'Building Confidence and Assertiveness', '471b8d71-13ad-4c43-bd70-34c2cffdfe03', 'Intermediate', 15, '[{"id": 1, "type": "mcq", "options": ["Identifying and challenging negative thoughts", "Positive self-talk", "Practicing assertive communication", "Avoiding social situations"], "question": "Which of the following is NOT a key element of building confidence?", "skill_tag": "Identifying confidence-building strategies", "difficulty": "easy", "correct_answer": "Avoiding social situations", "estimated_time": 45}, {"id": 2, "type": "mcq", "options": ["To avoid conflict at all costs", "To dominate others", "To passively accept others'' requests", "To clearly express your needs and boundaries"], "question": "What is the primary purpose of using assertive communication?", "skill_tag": "Understanding the purpose of assertive communication", "difficulty": "easy", "correct_answer": "To clearly express your needs and boundaries", "estimated_time": 45}, {"id": 3, "type": "mcq", "options": ["Increased anxiety and stress", "Decreased ability to take risks", "Greater resilience and adaptability", "Reduced ability to handle criticism"], "question": "Which of the following is a key benefit of building self-confidence?", "skill_tag": "Recognizing the benefits of self-confidence", "difficulty": "easy", "correct_answer": "Greater resilience and adaptability", "estimated_time": 45}, {"id": 4, "type": "mcq", "options": ["Confronting others directly", "Identifying your rights and needs", "Avoiding eye contact", "Practicing confident body language"], "question": "What is the first step in building assertiveness?", "skill_tag": "Recognizing the foundation of assertiveness", "difficulty": "easy", "correct_answer": "Identifying your rights and needs", "estimated_time": 45}, {"id": 5, "type": "mcq", "options": ["Celebrating small wins", "Surrounding yourself with supportive people", "Engaging in regular self-care", "Comparing yourself to others"], "question": "Which of the following is a common barrier to building confidence?", "skill_tag": "Identifying obstacles to building confidence", "difficulty": "easy", "correct_answer": "Comparing yourself to others", "estimated_time": 45}, {"id": 6, "type": "mcq", "options": ["Apologize and say you don''t have time to help", "Agree to help your colleague and miss your own deadline", "Ignore your colleague and continue working", "Firmly explain that you have a deadline and cannot assist right now"], "question": "You have a deadline for a project at work, but your colleague keeps interrupting you and asking for your help. How would you respond assertively?", "skill_tag": "Applying assertive communication in a workplace scenario", "difficulty": "medium", "correct_answer": "Firmly explain that you have a deadline and cannot assist right now", "estimated_time": 75}, {"id": 7, "type": "mcq", "options": ["Politely explain that you can no longer lend money and set clear boundaries", "Avoid the topic and continue lending money to maintain the friendship", "Confront your friend angrily and demand the money back", "Passive-aggressively refuse to lend money without providing an explanation"], "question": "Your friend constantly borrows money from you and never pays you back. What is the most assertive way to handle this situation?", "skill_tag": "Applying assertive communication in a personal relationship", "difficulty": "medium", "correct_answer": "Politely explain that you can no longer lend money and set clear boundaries", "estimated_time": 75}, {"id": 8, "type": "mcq", "options": ["Remain silent and accept that your ideas are not valued", "Interrupt others and demand that your ideas be heard", "Speak up confidently and explain the merits of your ideas", "Complain to your manager about the lack of respect"], "question": "You are in a meeting, and your ideas are consistently ignored by your team members. How can you assert yourself more effectively?", "skill_tag": "Asserting yourself in a group setting", "difficulty": "medium", "correct_answer": "Speak up confidently and explain the merits of your ideas", "estimated_time": 90}, {"id": 9, "type": "mcq", "options": ["Keeping a gratitude journal and celebrating your accomplishments", "Engaging in negative self-talk", "Focusing on your weaknesses and flaws", "Constantly seeking validation from others"], "question": "Which of the following is an effective technique for building self-confidence?", "skill_tag": "Applying self-reflection and positive reinforcement", "difficulty": "medium", "correct_answer": "Keeping a gratitude journal and celebrating your accomplishments", "estimated_time": 90}, {"id": 10, "type": "mcq", "options": ["Practice deep breathing and positive self-talk before the presentation", "Rely on others to deliver the presentation for you", "Avoid the presentation altogether to prevent anxiety", "Apologize to the audience for your anxiety and ask for their understanding"], "question": "You are feeling anxious about an upcoming presentation. How can you use assertiveness to manage your anxiety?", "skill_tag": "Applying assertiveness to manage emotions", "difficulty": "medium", "correct_answer": "Practice deep breathing and positive self-talk before the presentation", "estimated_time": 90}, {"id": 11, "type": "mcq", "options": ["Passively accept the additional tasks and hope for recognition", "Confront your boss aggressively and demand a raise", "Complain to HR about your boss''s unfair treatment", "Politely explain that the tasks are outside your role and negotiate fair compensation"], "question": "Your boss consistently assigns you tasks outside of your job description without additional compensation. How would you assertively address this issue?", "skill_tag": "Assertively addressing workplace boundary issues", "difficulty": "hard", "correct_answer": "Politely explain that the tasks are outside your role and negotiate fair compensation", "estimated_time": 100}, {"id": 12, "type": "mcq", "options": ["Threaten to end the relationship if your partner doesn''t change", "Completely give in to your partner''s decisions to avoid conflict", "Passive-aggressively express your displeasure and hope your partner notices", "Calmly explain your perspective, listen to your partner''s needs, and work towards a compromise"], "question": "You are in a romantic relationship, and your partner frequently makes decisions without considering your preferences. How can you assert your needs in a healthy way?", "skill_tag": "Assertively addressing relationship dynamics", "difficulty": "hard", "correct_answer": "Calmly explain your perspective, listen to your partner''s needs, and work towards a compromise", "estimated_time": 110}, {"id": 13, "type": "mcq", "options": ["Confront the person aggressively and demand an apology", "Passive-aggressively make a sarcastic remark in response", "Ignore the comment and avoid the person for the rest of the event", "Politely but firmly explain why the comment was inappropriate and ask the person to refrain from similar remarks"], "question": "You are at a social event, and someone makes an offensive comment. How can you assertively respond in a way that maintains your composure?", "skill_tag": "Assertively addressing inappropriate behavior in a social setting", "difficulty": "hard", "correct_answer": "Politely but firmly explain why the comment was inappropriate and ask the person to refrain from similar remarks", "estimated_time": 110}, {"id": 14, "type": "mcq", "options": ["Accept your manager''s decision and focus on your next project", "Passive-aggressively undermine your manager''s contributions to the project", "Confront your manager aggressively and threaten to quit", "Politely but firmly explain your role and contributions, and request appropriate recognition"], "question": "You have been working on a project for several months, and your manager wants to take credit for your work. How would you assertively address this situation?", "skill_tag": "Assertively addressing issues of recognition and credit", "difficulty": "hard", "correct_answer": "Politely but firmly explain your role and contributions, and request appropriate recognition", "estimated_time": 120}, {"id": 15, "type": "mcq", "options": ["Politely but firmly request the opportunity to share your perspective, and address the interruptions directly", "Remain silent and accept that your ideas will not be heard", "Complain to the group facilitator about the dominant member''s behavior", "Interrupt the dominant member and forcefully state your opinion"], "question": "You are in a group setting, and a dominant member consistently interrupts and dismisses your ideas. How can you assertively assert your voice?", "skill_tag": "Assertively navigating group dynamics", "difficulty": "hard", "correct_answer": "Politely but firmly request the opportunity to share your perspective, and address the interruptions directly", "estimated_time": 120}]', '2025-12-29 09:11:24.507415+00', 'AI', 1, '2025-12-29 09:11:24.507415+00', '2025-12-29 09:11:24.507415+00'),
